import{_ as p,o as n,c as i,ag as t}from"./chunks/framework.DXGyWiRo.js";const r="/images/uebung022.jpg",a="/images/uebung021.jpg",k=JSON.parse('{"title":"Übung Lektion 11","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung11.md","filePath":"lektionen/uebung11.md"}'),s={name:"lektionen/uebung11.md"};function o(h,e,m,u,d,l){return n(),i("div",null,[...e[0]||(e[0]=[t('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-11" tabindex="-1">Übung Lektion 11 <a class="header-anchor" href="#ubung-lektion-11" aria-label="Permalink to &quot;Übung Lektion 11&quot;">​</a></h1><p>A) Übersetzen Sie untenstehende Sätze</p><p>१. ऋषिः सत्यं वदति । Der vedische Weise spricht die Wahrheit.</p><p>२. ब्राह्मणः पुत्रमिच्छति । Ein Brahmane wünscht sich einen Sohn.</p><p>३. साधुः स्वर्गं गच्छति । Ein Heiliger kommt in den Himmel.</p><p>४. ब्राह्मणो ऽनृतं न वदतीति स्मृतिः । Die Smṛti sagt, dass ein Brahmane keine Unwahrheit spricht.</p><p>५. क्षत्रियो ब्राह्मणं धर्मं पृच्छति । Ein Kṣatriya fragt den Brahmanen nach dem Dharma.</p><p>६. एवं ब्राह्मणो यज्ञेन देवं यजति । So bringt der Brahmane dem Gott ein Opfer dar.</p><p>७. पुत्रः पापं करोतीति वैश्या मन्यते । Die Vaiśyafrau meint, dass ihr Sohn Böses tut.</p><p>८. क्षत्रियः क्षत्रियेण सह युध्यते । Kṣatriya kämpft mit Kṣatriya.</p><p>९. अधर्मो ऽनृतमिति पुत्रः पापं न करोति । Da Unwahrheit Unrecht ist, begeht der Sohn keine Übeltat.</p><p>१०. अयं क्षत्रियो धर्मं रक्षति । Dieser Kṣatriya behütet den Dharma.</p><p>११. को ऽग्निं यजते । Wer verehrt das Feuer (Gott Agni) mit einem Opfer?</p><p>१२. स श्रावको बुद्धं धर्मं पृच्छति ॥ Dieser Jünger befragt den Buddha über seine Lehre.</p><p>B) Setzen Sie die Sätze von A) in Passivkonstruktion</p><p>१. ऋषिणा सत्यमुद्यते ।</p><p>२. ब्राह्मणेन पुत्र इष्यते ।</p><p>३. साधुना स्वर्गो (स्वर्गं) गम्यत इति पुत्रेण पुण्यं क्रियते ।</p><p>४. ब्राह्मणेनानृतं नोद्यत इति स्मृतिः ।</p><p>५. क्षत्रियेण ब्राह्मणो धर्मं पृच्छ्यते ।</p><p>६. एवं ब्राह्मणेन यज्ञेन देव इज्यते ।</p><p>७. पुत्रेण पापं क्रियत इति वश्यया मन्यते ।</p><p>८. क्षत्रियेण क्षत्रियेण सह युध्यते ।</p><p>९. अधर्मो ऽनृतमिति पुत्रेण पापं न क्रियते ।</p><p>१०. अनेन क्षत्रियेण धर्मो रक्ष्यते ।</p><p>११. केनाग्निरिज्यते ।</p><p>१२. तेन श्रावकेण बुद्धो धर्मं पृच्छ्यते ॥</p><p>C) Setzen Sie in den Sätzen A), wo es sinnvoll ist, Subjekt, Objekt und Prädikat in den Plural</p><p>१. ऋषयः सत्यं वदन्ति ।</p><p>२. ब्राह्मणाः पुत्रानिच्छन्ति ।</p><p>३. साधवः स्वर्गान्गच्छन्तीति पुत्राः पुण्यं कुर्वन्ति ।</p><p>४. ब्राह्मणा अनृतं न वदन्तीति स्मृतिः ।</p><p>५. क्षत्रिया ब्राह्मणान्धर्मं पृच्छन्ति ।</p><p>६. एवं ब्राह्मणा यज्ञेन देवाण्यजन्ति ।</p><p>७. पुत्राह् पापं कुर्वन्तीति वैश्या मन्यन्ते ।</p><p>८. क्षत्रियाः क्षत्रियैः सह युध्यन्ते ।</p><p>९. अधर्मो ऽनृतमिति पुत्राः पापं न कुर्वन्ति ।</p><p>१०. इमे क्षत्रिया धर्मं रक्षन्ति ।</p><p>११. के (ऽग्निं) ऽग्नीन्यजन्ते ।</p><p>१२. ते श्रावका बुद्धं धर्मं पृच्छन्ति ॥</p><p>D) Bilden Sie zu den nach C) gebildeten Sätzen die Passivkonstruktion</p><p>१. ऋषिभिः सत्यमुद्यते ।</p><p>२. ब्राह्मणैः पुत्रा इष्यन्ते ।</p><p>३. साधुभिः स्वर्गा गम्यन्त इति पुत्रैः पुण्यं क्रियते ।</p><p>४. ब्राह्मणैरनृतं नोद्यत इति स्मृतिः ।</p><p>५. क्षत्रियैर्ब्राह्मणा धर्मं पृच्छ्य्न्ते ।</p><p>६. एवं ब्राह्मणैर्यज्ञेन देवा इज्यन्ते ।</p><p>७. पुत्रैः पापं क्रियत इति क्षत्रियाभिर्मन्यते ।</p><p>८. क्षत्रियैः क्षत्रियैः सह युध्यते ।</p><p>९. अधर्मो ऽनृतमिति पुत्रैः पापं न क्रियते ।</p><p>१०. एभिः क्षत्रियैर्धर्मो रक्ष्यते ।</p><p>११. कैरग्निरिज्यते । कैरग्नय इज्यन्ते ।</p><p>१२. तैः श्रावकैर्बुद्धो धर्मं प्र्च्छ्यते ॥</p><p><img src="'+r+'" alt=""><br> Abb.: केनाग्निरिज्यते ।<br>  Opfer, Shiva ashram, Kothavala, Ganeshpuri, 80 km von Mumbai (मुंबई) entfernt<br> [Bildquelle: Dey. -- <a href="http://www.flickr.com/photos/dey/466769475/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/dey/466769475/</a>.  -- Zugriff am 2008-12-06. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Comons Lizenz (Namensnennung, keine kommerzielle Nutzung, Share alike)]</p><p>A) Übersetzen Sie ins Sanskrit mit Passivkonstruktionen:</p><p>1. Vaiśyafrauen fragen Brahmanen nach dem Dharma.</p><p>वैश्याभिर्ब्राह्मणो धर्मं पृच्छ्यते ।</p><p>2. Der Lehrer spricht ein Mantra.</p><p>गुरुणा मन्त्र उद्यते ।</p><p>3. Heilige Frauen gelangen in einen Himmel.</p><p>साध्वीभिः स्वर्ग आप्यते । स्वर्गो ऽश्यते । स्वर्गो गम्यते । स्वर्गं गम्यते ।</p><p>4. Ein vedischer Weiser tut nichts Böses.</p><p>ऋषिणा पापं न क्रियते ।</p><p>5. Brahmanen verehren als Opferpriester die Göttin mit Opfern.</p><p>ब्राह्मनैर्देवीज्यते ।</p><p>6. Die Śūdrafrau geht ins Dorf.</p><p>7. Wer sieht die  Wahrheit?</p><p>केन सत्यं दृश्यते ॥</p><p>B)</p><p>1. Geben Sie mit einem Dvandva die Aufgaben aller Zweimalgeborenen an. Lösen Sie das Kompositum in Sanskrit auf.</p><p>इज्याध्ययनदानानि = इज्याध्ययनं दानं च</p><p>2. Geben Sie mit einem Dvandva die Aufgaben der Vaiśyas an. Lösen Sie das Kompositum in Sanskrit auf.</p><p>कृषिवाणिज्यपाशुपाल्यकुसीदानि = कृषीर्वाणिज्यं (वाणिज्या, वणिज्या) कुसीदं च ।</p><p>C) Übersetzen Sie:</p><p>१. श्रवणेन श्रूयते । Das Ohr hört. Mit dem Ohr hört man.</p><p>२. कर्षकैः कृष्यते । Ackerbauern pflügen.</p><p>३. श्रावकेणेश्वरो नेज्यते । Ein Buddhaanhänger opfert keinem HERRN.</p><p>४. रक्षिक्या गुरू रक्ष्यते । Das Amulett beschützt den Meister.</p><p>५. ब्राह्मणेनानृतं नोद्यते । Ein Brahmane spricht keine Unwahrheit</p><p>६. शूद्रेतरा । Itarā ist eine Śūdrafrau.</p><p>७. शिक्षा कल्पो व्याकरणं निरुक्तं छन्दो ज्योतिषमङ्गानि । Hilfswissenschaften zum Veda sind: Aussprachelehre, Ritualistik, Grammatik, Wortbedeutungslehre, Metrik und Kalenderlehre</p><p>८. आन्वीक्षिकीत्रयीवार्त्तादण्डनीतयो विद्याः ॥ Wissenschaften sind: Philosophie, Vedistik, Ökonomie und Politologie.</p><p>D) Übersetzen Sie und setzen Sie in Sanskrit Agens, Objekt und Verb in den Plural:</p><p>१. फलमश्नुते । Er bekommt eine Frucht. फलान्यश्नुवन्ते ।</p><p>२. गुरुणा सत्यमुद्यते । Der Meister spricht die Wahrheit. गुरुभिः सत्यान्युद्यन्ते ।</p><p>३. वैश्यः पशुं लभते । Der Vaiśya erhält Vieh. वैश्याः पशुंल्लभन्ते ।</p><p>४. पुत्रः पुण्यं करोति ॥ Mein Sohn tut Verdienstvolles. पुत्राः पुण्यानि कुर्वन्ति ॥</p><p>E) Verwandeln Sie die Sätze C)1-5 in Aktivkonstruktionen.</p><p>१. श्रवणं शृणोति ।</p><p>२. कर्षकाः कृषन्ति ।</p><p>३. श्रावक ईश्वरं न यजते ।</p><p>४. रक्षिका गुरुं रक्षति ।</p><p>५. ब्राह्मनो ऽनृतं न वदति ॥</p><p><img src="'+a+'" alt=""><br> Abb.: फलान्यश्नुते<br> Mysore = ಮೈಸೂರು<br> [Bildquelle: PnP!. -- <a href="http://www.flickr.com/photos/pnp/1596379612/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/pnp/1596379612/</a>. -- Zugriff am 2008-12-06. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p>',95)])])}const g=p(s,[["render",o]]);export{k as __pageData,g as default};
